// Product Details page - shows info for one product
import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';

function ProductDetails() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    console.log('getting product id:', id);
    fetch('/products/')
      .then(function(res) {
        return res.json();
      })
      .then(function(data) {
        console.log('product data:', data);
        setProduct(data);
        setLoading(false);
      })
      .catch(function(err) {
        console.log('error:', err);
        setLoading(false);
      });
  }, [id]);

  function addToCart() {
    var cart = JSON.parse(localStorage.getItem('cart')) || [];
    var found = cart.find(function(item) { return item.id === product.id; });

    if (found) {
      found.quantity = found.quantity + 1;
    } else {
      var productToAdd = {
        id: product.id,
        name: product.name,
        price: product.price,
        image: product.image,
        quantity: 1
      };
      cart.push(productToAdd);
    }

    localStorage.setItem('cart', JSON.stringify(cart));
    alert(product.name + ' added to cart!');
  }

  if (loading) {
    return (
      <div className="container mt-4">
        <p>Loading product...</p>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="container mt-4">
        <p>Product not found!</p>
        <Link to="/products" className="btn btn-primary">Back to Products</Link>
      </div>
    );
  }

  return (
    <div className="container mt-4">
      {/* back button */}
      <Link to="/products" className="btn btn-outline-secondary mb-3">
        ← Back to Products
      </Link>

      <div className="row">
        {/* product image */}
        <div className="col-md-5">
          <img
            src={'/images/' + product.image}
            alt={product.name}
            className="img-fluid rounded border"
            style={{ width: '100%', height: '350px', objectFit: 'cover' }}
          />
        </div>

        {/* product info */}
        <div className="col-md-7">
          <h2>{product.name}</h2>
          <hr />
          <p className="text-muted">{product.description}</p>
          <h3 className="text-success">${product.price}</h3>
          <p className="text-muted small">Product ID: #{product.id}</p>

          <div className="d-flex gap-3 mt-3">
            <button className="btn btn-success btn-lg" onClick={addToCart}>
              🛒 Add to Cart
            </button>
            <Link to="/cart" className="btn btn-outline-dark btn-lg">
              View Cart
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
